mapper.select:
SELECT O.ORDER_NO, O.ORDER_ID, TO_CHAR(O.ORDER_DATE, 'YYYY-MM-DD HH24:MI') AS ORDER_DATE, O.ORDER_STATUS, O.RECIPIENT, O.RECIPIENT_TEL, O.BASIC_ADDRESS, O.DETAIL_ADDRESS, O.POSTCODE, O.TOTAL_AMOUNT, O.PAYMENT_METHOD, O.DELIVERY_COMPANY, O.TRACKING_NUMBER, M.MEMBER_EMAIL, (SELECT COUNT(*) FROM ORDER_ITEM WHERE ORDER_NO = O.ORDER_NO) AS TOTAL_ITEM_COUNT, (SELECT G.GOODS_NAME FROM ORDER_ITEM OI JOIN GOODS G ON OI.GOODS_NO = G.GOODS_NO WHERE OI.ORDER_NO = O.ORDER_NO AND ROWNUM = 1) AS FIRST_GOODS_NAME FROM TOTAL_ORDER O JOIN MEMBER M ON O.MEMBER_NO = M.MEMBER_NO
O.ORDER_STATUS = #{status}
ORDER BY O.ORDER_NO DESC

